INSERT INTO training_questions (grand_quiz_id, source_question_id, question_text, options, correct_option, order_index, is_active) SELECT g.id, 4217, 'Define your Lesson Objective. Choose one English Language Teaching (ELT) topic from your syllabus (e.g., Subject–Verb Agreement, Descriptive Paragraph Writing, or Active Listening). Identify a clear Lesson Objective based on a related SLO from the National Curriculum that describes what the student will be able to do with the language. Your objective must use a clear action verb that targets a specific language skill (e.g., Summarize a story, Apply past tense in a role-play, or Analyze Tier 2 vocabulary).', '[]'::jsonb, '', 1, true FROM training_grand_quizzes g WHERE g.source_quiz_id=8 AND g.quiz_type='capstone' AND NOT EXISTS (SELECT 1 FROM training_questions WHERE source_question_id=4217);
INSERT INTO training_questions (grand_quiz_id, source_question_id, question_text, options, correct_option, order_index, is_active) SELECT g.id, 4218, 'Write your AI Prompt. Use an AI tool to help you brainstorm lesson ideas or generate classroom content (such as a reading passage or a role-play script) that matches your objective. Show the exact prompt you used. It must follow the Role + Task + Context + Output Format formula.', '[]'::jsonb, '', 2, true FROM training_grand_quizzes g WHERE g.source_quiz_id=8 AND g.quiz_type='capstone' AND NOT EXISTS (SELECT 1 FROM training_questions WHERE source_question_id=4218);
INSERT INTO training_questions (grand_quiz_id, source_question_id, question_text, options, correct_option, order_index, is_active) SELECT g.id, 4219, 'Describe one activity for your lesson using a Modern Pedagogy. The activity must directly build toward the Lesson Objective you set in Question 1. Choose one or a mix of: Task-Based Learning (TBL) where students complete a meaningful task focusing on meaning before grammar; Communicative Language Teaching (CLT) where students interact in real-life scenarios; or Three-Stage Reading Approach moving through Pre-Reading, While-Reading, and Post-Reading stages.', '[]'::jsonb, '', 3, true FROM training_grand_quizzes g WHERE g.source_quiz_id=8 AND g.quiz_type='capstone' AND NOT EXISTS (SELECT 1 FROM training_questions WHERE source_question_id=4219);
INSERT INTO training_questions (grand_quiz_id, source_question_id, question_text, options, correct_option, order_index, is_active) SELECT g.id, 4220, 'Design a Performance Assessment task that requires students to perform a language skill. This must be non-quiz based and reflect a real-life communicative task. Examples: writing an advertisement, telling a story, or participating in a debate. The task must directly measure the objective you wrote in Question 1.', '[]'::jsonb, '', 4, true FROM training_grand_quizzes g WHERE g.source_quiz_id=8 AND g.quiz_type='capstone' AND NOT EXISTS (SELECT 1 FROM training_questions WHERE source_question_id=4220);
INSERT INTO training_questions (grand_quiz_id, source_question_id, question_text, options, correct_option, order_index, is_active) SELECT g.id, 4221, 'Design an Analytic Rubric to evaluate the performance task from Question 4. Your rubric must break performance into separate criteria (e.g., Content, Language, Delivery) and include clear descriptors for at least three levels: Outstanding, Successful, and Needs Improvement.', '[]'::jsonb, '', 5, true FROM training_grand_quizzes g WHERE g.source_quiz_id=8 AND g.quiz_type='capstone' AND NOT EXISTS (SELECT 1 FROM training_questions WHERE source_question_id=4221);
INSERT INTO training_questions (grand_quiz_id, source_question_id, question_text, options, correct_option, order_index, is_active) SELECT g.id, 4222, 'Convert your rubric into a Student-Facing Success Scale using "I Can..." statements. Use the "I Can..." format so students understand what success looks like and can take ownership of their progress. Each statement should correspond to a level in your rubric.', '[]'::jsonb, '', 6, true FROM training_grand_quizzes g WHERE g.source_quiz_id=8 AND g.quiz_type='capstone' AND NOT EXISTS (SELECT 1 FROM training_questions WHERE source_question_id=4222);
INSERT INTO training_questions (grand_quiz_id, source_question_id, question_text, options, correct_option, order_index, is_active) SELECT g.id, 4223, 'In 3–4 sentences, explain how you ensured your activity and assessment directly support your Lesson Objective. Explain why this is a "matched" lesson — how does the performance task prove students met the objective?', '[]'::jsonb, '', 7, true FROM training_grand_quizzes g WHERE g.source_quiz_id=8 AND g.quiz_type='capstone' AND NOT EXISTS (SELECT 1 FROM training_questions WHERE source_question_id=4223);
INSERT INTO training_questions (grand_quiz_id, source_question_id, question_text, options, correct_option, order_index, is_active) SELECT g.id, 4224, 'Briefly state one action you took to ensure the AI''s output was safe and accurate for your classroom. Mention how you verified facts, checked for cultural or regional bias, or ensured student privacy was protected.', '[]'::jsonb, '', 8, true FROM training_grand_quizzes g WHERE g.source_quiz_id=8 AND g.quiz_type='capstone' AND NOT EXISTS (SELECT 1 FROM training_questions WHERE source_question_id=4224);
INSERT INTO training_questions (grand_quiz_id, source_question_id, question_text, options, correct_option, order_index, is_active) SELECT g.id, 4225, 'Choose one mathematics topic covered in this course (e.g., Number Theory, Angle Measurement, Statistics, or Fractions). Select a related Student Learning Outcome (SLO) from the National Curriculum and break it down into 3–4 clear Lesson Objectives. Each objective must use an action verb from the Revised Bloom''s Taxonomy.', '[]'::jsonb, '', 1, true FROM training_grand_quizzes g WHERE g.source_quiz_id=9 AND g.quiz_type='capstone' AND NOT EXISTS (SELECT 1 FROM training_questions WHERE source_question_id=4225);
INSERT INTO training_questions (grand_quiz_id, source_question_id, question_text, options, correct_option, order_index, is_active) SELECT g.id, 4226, 'Use an AI tool to help you brainstorm unstructured lesson ideas or strategic hints that match your objective. Show the exact prompt you used. It must follow the Role + Task + Context + Output Format formula.', '[]'::jsonb, '', 2, true FROM training_grand_quizzes g WHERE g.source_quiz_id=9 AND g.quiz_type='capstone' AND NOT EXISTS (SELECT 1 FROM training_questions WHERE source_question_id=4226);
INSERT INTO training_questions (grand_quiz_id, source_question_id, question_text, options, correct_option, order_index, is_active) SELECT g.id, 4227, 'Describe one activity for your lesson using a Modern Pedagogy. The activity must directly build toward the Lesson Objective. Choose one or a mix of: Unstructured Activity (students decide what information is relevant and choose their own solution strategies), Collaborative Learning (students work in teams using Ground Rules for Discussion to foster Exploratory Talk), or Inquiry-Based Learning (students investigate a What-If scenario, e.g., "What happens to area if the radius doubles?").', '[]'::jsonb, '', 3, true FROM training_grand_quizzes g WHERE g.source_quiz_id=9 AND g.quiz_type='capstone' AND NOT EXISTS (SELECT 1 FROM training_questions WHERE source_question_id=4227);
INSERT INTO training_questions (grand_quiz_id, source_question_id, question_text, options, correct_option, order_index, is_active) SELECT g.id, 4228, 'Define the final performance task students must complete to prove they have met the objective. Describe a Performance Task (e.g., creating a poster, presenting a reasoning-based solution, or designing a geometric model). Avoid standard MCQs; focus on higher-order thinking where students must justify their answers.', '[]'::jsonb, '', 4, true FROM training_grand_quizzes g WHERE g.source_quiz_id=9 AND g.quiz_type='capstone' AND NOT EXISTS (SELECT 1 FROM training_questions WHERE source_question_id=4228);
INSERT INTO training_questions (grand_quiz_id, source_question_id, question_text, options, correct_option, order_index, is_active) SELECT g.id, 4229, 'Design a Qualitative Assessment Rubric to evaluate the performance task from Question 4. Select 2–3 key criteria (e.g., Mathematical Reasoning, Accuracy, Explanation). Use 3 performance levels: Strong, Developing, Emerging. Write clear descriptors for each level. Include feedback that helps students understand how to improve.', '[]'::jsonb, '', 5, true FROM training_grand_quizzes g WHERE g.source_quiz_id=9 AND g.quiz_type='capstone' AND NOT EXISTS (SELECT 1 FROM training_questions WHERE source_question_id=4229);
