INSERT INTO training_questions (grand_quiz_id, source_question_id, question_text, options, correct_option, order_index, is_active) SELECT g.id, 4235, 'Describe one activity for your lesson using a Modern Pedagogy. The activity must directly build toward the Lesson Objective. Choose one or a mix of: Active Learning (students act out or do the concept), Collaborative Learning (students work in structured teams), or Inquiry-Based Learning (students investigate a What-If scenario to test how a system works).', '[]'::jsonb, '', 3, true FROM training_grand_quizzes g WHERE g.source_quiz_id=10 AND g.quiz_type='capstone' AND NOT EXISTS (SELECT 1 FROM training_questions WHERE source_question_id=4235);
INSERT INTO training_questions (grand_quiz_id, source_question_id, question_text, options, correct_option, order_index, is_active) SELECT g.id, 4236, 'Define the final performance task students must complete to prove they have met the objective. Describe a Performance Task such as a short coding challenge, a completed flowchart, or a debugging exercise. This task must measure the exact same skill defined in your objectives. Avoid MCQs or recall-based questions.', '[]'::jsonb, '', 4, true FROM training_grand_quizzes g WHERE g.source_quiz_id=10 AND g.quiz_type='capstone' AND NOT EXISTS (SELECT 1 FROM training_questions WHERE source_question_id=4236);
INSERT INTO training_questions (grand_quiz_id, source_question_id, question_text, options, correct_option, order_index, is_active) SELECT g.id, 4237, 'Translate your teacher-level assessment criteria into a Student-Facing Success Scale. Use the "I Can..." format so students understand what success looks like and can take ownership of their progress. Write 3–4 statements. Example: Instead of "Student uses correct syntax", write "I can find and fix small errors when my code doesn''t run".', '[]'::jsonb, '', 5, true FROM training_grand_quizzes g WHERE g.source_quiz_id=10 AND g.quiz_type='capstone' AND NOT EXISTS (SELECT 1 FROM training_questions WHERE source_question_id=4237);
