INSERT INTO training_questions (grand_quiz_id, source_question_id, question_text, options, correct_option, order_index, is_active) SELECT g.id, 4240, 'Review your full submission. Describe how you have organized each section and ensured it is complete, concise, and easy to follow. Is anything missing or unclear?', '[]'::jsonb, '', 7, true FROM training_grand_quizzes g WHERE g.source_quiz_id=10 AND g.quiz_type='capstone' AND NOT EXISTS (SELECT 1 FROM training_questions WHERE source_question_id=4240);
INSERT INTO training_questions (grand_quiz_id, source_question_id, question_text, options, correct_option, order_index, is_active) SELECT g.id, 4241, 'Before designing your lesson, use an AI tool to help brainstorm activities or draft your rubric. Write a Refined Prompt using the Role + Task + Context + Output Format formula. Then show at least one Iterative Refinement: if the first response was too vague, show how you asked the AI to "revise, simplify, or improve the output" to better fit a large classroom or specific student needs.', '[]'::jsonb, '', 1, true FROM training_grand_quizzes g WHERE g.source_quiz_id=11 AND g.quiz_type='capstone' AND NOT EXISTS (SELECT 1 FROM training_questions WHERE source_question_id=4241);
INSERT INTO training_questions (grand_quiz_id, source_question_id, question_text, options, correct_option, order_index, is_active) SELECT g.id, 4242, 'Describe the Problem Definition for your lesson (the Ask Stage of the Engineering Design Process). Identify the real-world problem students will solve and the specific constraints they must work within.', '[]'::jsonb, '', 2, true FROM training_grand_quizzes g WHERE g.source_quiz_id=11 AND g.quiz_type='capstone' AND NOT EXISTS (SELECT 1 FROM training_questions WHERE source_question_id=4242);
INSERT INTO training_questions (grand_quiz_id, source_question_id, question_text, options, correct_option, order_index, is_active) SELECT g.id, 4243, 'Describe your full Engineering Design Process (EDP) Implementation Plan covering all 5 stages: Ask (identify problem and constraints), Imagine & Plan (research, brainstorm, sketch designs), Create (build prototype using low-cost materials), Test (gather data on how well the design works), and Improve (mandatory feedback and fix stage using test results). For each stage, describe what students will DO and what the output will be.', '[]'::jsonb, '', 3, true FROM training_grand_quizzes g WHERE g.source_quiz_id=11 AND g.quiz_type='capstone' AND NOT EXISTS (SELECT 1 FROM training_questions WHERE source_question_id=4243);
INSERT INTO training_questions (grand_quiz_id, source_question_id, question_text, options, correct_option, order_index, is_active) SELECT g.id, 4244, 'Describe the hands-on activity where students actively design, build, and test a prototype. What low-cost materials will they use? How are students actively engaged in the engineering process rather than just watching?', '[]'::jsonb, '', 4, true FROM training_grand_quizzes g WHERE g.source_quiz_id=11 AND g.quiz_type='capstone' AND NOT EXISTS (SELECT 1 FROM training_questions WHERE source_question_id=4244);
INSERT INTO training_questions (grand_quiz_id, source_question_id, question_text, options, correct_option, order_index, is_active) SELECT g.id, 4245, 'Design a Conceptual Exit Ticket to be used after the Test stage of the EDP. Write one higher-order question that asks students to explain a phenomenon related to their design (not just recall a definition). This question should help you identify gaps in scientific reasoning before students move to the Improve stage.', '[]'::jsonb, '', 5, true FROM training_grand_quizzes g WHERE g.source_quiz_id=11 AND g.quiz_type='capstone' AND NOT EXISTS (SELECT 1 FROM training_questions WHERE source_question_id=4245);
INSERT INTO training_questions (grand_quiz_id, source_question_id, question_text, options, correct_option, order_index, is_active) SELECT g.id, 4246, 'Describe how you will use the Exit Ticket responses to provide actionable feedback. Rather than marking answers "wrong", how will you prompt students toward the correct scientific principle before they move to the Improve stage?', '[]'::jsonb, '', 6, true FROM training_grand_quizzes g WHERE g.source_quiz_id=11 AND g.quiz_type='capstone' AND NOT EXISTS (SELECT 1 FROM training_questions WHERE source_question_id=4246);
INSERT INTO training_questions (grand_quiz_id, source_question_id, question_text, options, correct_option, order_index, is_active) SELECT g.id, 4247, 'Describe the Summative Assessment for your unit. Students must present their final improved prototype along with a Model-Based Explanation. They must justify their final design choices using evidence collected during the Test stage. Assessment should focus on the entire design cycle, including how students managed failure and iteration.', '[]'::jsonb, '', 7, true FROM training_grand_quizzes g WHERE g.source_quiz_id=11 AND g.quiz_type='capstone' AND NOT EXISTS (SELECT 1 FROM training_questions WHERE source_question_id=4247);
INSERT INTO training_questions (grand_quiz_id, source_question_id, question_text, options, correct_option, order_index, is_active) SELECT g.id, 4248, 'Explain how your formative assessment (Exit Ticket) and summative assessment (Performance Task) are aligned to the EDP stages, especially the Test → Improve cycle. How do your assessments measure learning from the engineering process, not just the final product?', '[]'::jsonb, '', 8, true FROM training_grand_quizzes g WHERE g.source_quiz_id=11 AND g.quiz_type='capstone' AND NOT EXISTS (SELECT 1 FROM training_questions WHERE source_question_id=4248);
INSERT INTO training_questions (grand_quiz_id, source_question_id, question_text, options, correct_option, order_index, is_active) SELECT g.id, 4249, 'Create an original Analytic Rubric for your summative performance task. Select 3–5 dimensions of performance (e.g., Scientific Accuracy, Design Reasoning, Iterative Improvement, Use of Evidence). Create 3–4 performance levels (e.g., Beginning, Proficient, Advanced). Write specific, observable descriptors for each cell — avoid vague terms like "good".', '[]'::jsonb, '', 9, true FROM training_grand_quizzes g WHERE g.source_quiz_id=11 AND g.quiz_type='capstone' AND NOT EXISTS (SELECT 1 FROM training_questions WHERE source_question_id=4249);
INSERT INTO training_questions (grand_quiz_id, source_question_id, question_text, options, correct_option, order_index, is_active) SELECT g.id, 4250, 'Describe your plan to share this rubric with students BEFORE the task begins. How will you use it to support student understanding and ownership of the task expectations?', '[]'::jsonb, '', 10, true FROM training_grand_quizzes g WHERE g.source_quiz_id=11 AND g.quiz_type='capstone' AND NOT EXISTS (SELECT 1 FROM training_questions WHERE source_question_id=4250);
