BEGIN;
-- bd-2233: answers table columns for open-ended capstone answers (nullable, additive)
ALTER TABLE training_assessment_answers ADD COLUMN IF NOT EXISTS answer_text text;
ALTER TABLE training_assessment_answers ADD COLUMN IF NOT EXISTS answer_score smallint;
ALTER TABLE training_assessment_answers ADD COLUMN IF NOT EXISTS feedback_text text;
-- widen chosen_option for multi-select sets on 10-option questions (defensive)
ALTER TABLE training_assessment_answers ALTER COLUMN chosen_option TYPE varchar(32);

-- bd-2233: BH capstone grand-quiz rows (quiz_type='capstone' keeps every MCQ path inert)

-- bd-2233: the open-ended questions (empty options + empty correct_option = open-ended)
COMMIT;
SELECT g.level_id, count(q.id) AS questions FROM training_grand_quizzes g LEFT JOIN training_questions q ON q.grand_quiz_id=g.id WHERE g.quiz_type='capstone' GROUP BY 1 ORDER BY 1;
